@import "tailwindcss";
@import "tw-animate-css";

/* ── Fonts ─────────────────────────────────────────────── */

@font-face {
  font-family: "Geist Sans";
  font-style: normal;
  font-weight: 100 900;
  font-display: swap;
  src: url("./fonts/Geist-Variable.woff2") format("woff2");
}

@font-face {
  font-family: "Geist Mono";
  font-style: normal;
  font-weight: 100 900;
  font-display: swap;
  src: url("./fonts/GeistMono-Variable.woff2") format("woff2");
}

/* ── Variants ──────────────────────────────────────────── */

@custom-variant dark (&:is(.dark *));

/* ── Theme: Semantic Colors, Fonts, Easing ─────────────── */

@theme {
  --font-sans: "Geist Sans", ui-sans-serif, system-ui, sans-serif;
  --font-mono: "Geist Mono", ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace;

  --color-warning: oklch(0.75 0.18 60);
  --color-success: oklch(0.62 0.17 150);
  --color-info: oklch(0.65 0.15 240);

  --color-diff-add: oklch(0.35 0.1 150);
  --color-diff-remove: oklch(0.3 0.1 25);
  --color-diff-add-text: oklch(0.75 0.15 150);
  --color-diff-remove-text: oklch(0.75 0.15 25);

  --ease-smooth: cubic-bezier(0.16, 1, 0.3, 1);
  --ease-snappy: cubic-bezier(0.2, 0, 0, 1);
}

/* ── Theme: shadcn Variable Bridge ─────────────────────── */

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);
  --radius-sm: calc(var(--radius) - 4px);
  --radius-md: calc(var(--radius) - 2px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
}

/* ── Light Mode (kept minimal, dark-first app) ─────────── */

:root {
  --background: oklch(0.985 0 0);
  --foreground: oklch(0.145 0 0);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.145 0 0);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.145 0 0);
  --primary: oklch(0.55 0.15 85);
  --primary-foreground: oklch(0.985 0 0);
  --secondary: oklch(0.95 0.005 85);
  --secondary-foreground: oklch(0.25 0 0);
  --muted: oklch(0.96 0 0);
  --muted-foreground: oklch(0.45 0 0);
  --accent: oklch(0.96 0 0);
  --accent-foreground: oklch(0.25 0 0);
  --destructive: oklch(0.58 0.22 27);
  --destructive-foreground: oklch(0.985 0 0);
  --border: oklch(0 0 0 / 8%);
  --input: oklch(0 0 0 / 12%);
  --ring: oklch(0.55 0.15 85);
  --radius: 0.375rem;
}

/* ── Dark Mode (primary theme) ─────────────────────────── */

.dark {
  --background: oklch(0.085 0.005 260);
  --foreground: oklch(0.93 0.005 260);
  --card: oklch(0.115 0.005 260);
  --card-foreground: oklch(0.93 0.005 260);
  --popover: oklch(0.135 0.005 260);
  --popover-foreground: oklch(0.93 0.005 260);
  --primary: oklch(0.75 0.15 85);
  --primary-foreground: oklch(0.15 0 0);
  --secondary: oklch(0.16 0.005 260);
  --secondary-foreground: oklch(0.93 0.005 260);
  --muted: oklch(0.16 0.005 260);
  --muted-foreground: oklch(0.55 0.005 260);
  --accent: oklch(0.16 0.005 260);
  --accent-foreground: oklch(0.93 0.005 260);
  --destructive: oklch(0.65 0.2 25);
  --destructive-foreground: oklch(0.985 0 0);
  --border: oklch(1 0 0 / 8%);
  --input: oklch(1 0 0 / 12%);
  --ring: oklch(0.75 0.15 85);
}

/* ── Base Layer ────────────────────────────────────────── */

@layer base {
  * {
    @apply border-border outline-ring/50;
  }

  body {
    @apply bg-background text-foreground text-sm antialiased;
    font-feature-settings: "cv02", "cv03", "cv04", "cv11";
  }

  ::selection {
    background: color-mix(in oklch, var(--primary) 30%, transparent);
  }

  ::-webkit-scrollbar {
    width: 6px;
    height: 6px;
  }

  ::-webkit-scrollbar-track {
    background: transparent;
  }

  ::-webkit-scrollbar-thumb {
    background: var(--border);
    border-radius: 3px;
  }

  ::-webkit-scrollbar-thumb:hover {
    background: var(--input);
  }
}

